pragma solidity ^0.8.7;

import { TestBaseWithAssertions } from "../../../TestBaseWithAssertions.sol";

contract SetManualWithdrawalTests is TestBaseWithAssertions {

    address lp;
    address wm;

    function setUp() public override {
        start = block.timestamp;

        _createAccounts();
        _createAssets();
        _createGlobals();
        _setTreasury();
        _createFactories();
        _createPoolWithQueue();
        _configurePool();

        openPool(address(poolManager));

        lp = makeAddr("lp");
        wm = address(queueWM);

        deposit(lp, 1_000e6);
    }

    function test_setManualWithdrawal_failIfProtocolIsPaused() external {
        vm.prank(governor);
        globals.setProtocolPause(true);

        vm.expectRevert("WM:PAUSED");
        vm.prank(poolDelegate);
        queueWM.setManualWithdrawal(lp, true);
    }

    function test_setManualWithdrawal_failIfNotProtocolAdmin() external {
        vm.expectRevert("WM:NOT_PD_OR_GOV_OR_OA");
        queueWM.setManualWithdrawal(lp, true);
    }

    function test_setManualWithdrawal_failIfLpAlreadyInQueue() external {
        requestRedeem(lp, 1_000e6);

        vm.expectRevert("WM:SMW:IN_QUEUE");
        vm.prank(poolDelegate);
        queueWM.setManualWithdrawal(lp, true);
    }

    function test_setManualWithdrawal_success() external {
        vm.prank(poolDelegate);
        queueWM.setManualWithdrawal(lp, true);

        assertTrue(queueWM.isManualWithdrawal(lp));
    }

    function test_setManualWithdrawal_successAsGovernor() external {
        vm.prank(governor);
        queueWM.setManualWithdrawal(lp, true);

        assertTrue(queueWM.isManualWithdrawal(lp));
    }

    function test_setManualWithdrawal_successAsOperationalAdmin() external {
        vm.prank(operationalAdmin);
        queueWM.setManualWithdrawal(lp, true);

        assertTrue(queueWM.isManualWithdrawal(lp));
    }

    function test_setManualWithdrawal_unsetSuccess() external {
        vm.prank(poolDelegate);
        queueWM.setManualWithdrawal(lp, true);

        assertTrue(queueWM.isManualWithdrawal(lp));

        vm.prank(poolDelegate);
        queueWM.setManualWithdrawal(lp, false);

        assertFalse(queueWM.isManualWithdrawal(lp));
    }

}

// SPDX-License-Identifier: MIT

pragma solidity =0.8.24;

contract MockChainlinkFeedRegistry {
    struct PriceData {
        uint80 roundId;
        int256 answer;
        uint256 startedAt;
        uint256 updatedAt;
        uint80 answeredInRound;
        uint256 index;
    }

    mapping(address => mapping(address => mapping(uint80 => PriceData))) prices;

    uint80[] public roundIds;

    uint80 latestRoundId;

    function setRoundData(address _base, address _quote, uint80 _roundId, int256 _answer) public {
        roundIds.push(_roundId);

        prices[_base][_quote][_roundId] = PriceData({
            roundId: _roundId,
            answer: _answer,
            startedAt: block.timestamp,
            updatedAt: block.timestamp,
            answeredInRound: _roundId,
            index: roundIds.length - 1
        });

        latestRoundId = _roundId;
    }

    function latestRoundData(address base, address quote)
        external
        view
        returns (
            uint80 roundId,
            int256 answer,
            uint256 startedAt,
            uint256 updatedAt,
            uint80 answeredInRound
        )
    {
        PriceData memory p = prices[base][quote][latestRoundId];
        return (p.roundId, p.answer, p.startedAt, p.updatedAt, p.answeredInRound);
    }

    function getRoundData(address base, address quote, uint80 _roundId)
        external
        view
        returns (
            uint80 roundId,
            int256 answer,
            uint256 startedAt,
            uint256 updatedAt,
            uint80 answeredInRound
        )
    {
        if (_roundId == 0) {
            _roundId = latestRoundId;
        }

        PriceData memory p = prices[base][quote][_roundId];
        return (p.roundId, p.answer, p.startedAt, p.updatedAt, p.answeredInRound);
    }

    function getNextRoundId(address base, address quote, uint80 roundId)
        external
        view
        returns (uint80 nextRoundId)
    {
        PriceData memory p = prices[base][quote][roundId];

        if (p.index + 1 >= roundIds.length) return 0;

        return roundIds[p.index + 1];
    }

    function getFeed(address, address) public pure returns (address) {
        return 0xE62B71cf983019BFf55bC83B48601ce8419650CC;
    }
}

// SPDX-License-Identifier: MIT

pragma solidity =0.8.24;

interface IUmbrellaDataAggregator {
    enum TokenType {
        None,
        Token,
        AToken,
        StataToken
    }

    struct StakeTokenData {
        TokenData stakeTokenData;
        uint256 totalAssets;
        uint256 targetLiquidity;
        bool isStakeConfigured;
        RewardTokenData[] rewardsTokenData;
    }

    struct RewardTokenData {
        TokenData rewardTokenData;
        uint256 maxEmissionPerSecond;
        uint256 distributionEnd;
    }

    struct TokenRouteData {
        address stakeToken;
        TokenFromRoute[] tokensFromRoute;
    }

    struct TokenFromRoute {
        TokenType typeOfToken;
        TokenData tokenData;
    }

    struct TokenData {
        address token;
        uint256 price;
        string name;
        string symbol;
        uint8 decimals;
    }

    struct StakeTokenUserData {
        address stakeToken;
        uint256 stakeUserBalance;
        RewardTokenUserData[] rewardsTokenUserData;
    }

    struct RewardTokenUserData {
        address reward;
        uint256 currentReward;
    }

    struct TokenRouteBalances {
        address stakeToken;
        BalanceOfTokenFromRoute[] balancesOfRouteTokens;
    }

    struct BalanceOfTokenFromRoute {
        TokenType typeOfToken;
        address token;
        uint256 userBalance;
    }

    function getAllAggregatedData(address _umbrella, address _aaveOracle, address _user)
        external
        view
        returns (
            StakeTokenData[] memory,
            TokenRouteData[] memory,
            StakeTokenUserData[] memory,
            TokenRouteBalances[] memory
        );

    function getTokensAggregatedData(address _umbrella, address _aaveOracle)
        external
        view
        returns (StakeTokenData[] memory);

    function getUserAggregatedData(address _umbrella, address _user)
        external
        view
        returns (StakeTokenUserData[] memory);
}
